// Extract incoming Telegram message data
const body = $input.item.json.body;

// Handle if body is already parsed or needs parsing
const data = typeof body === 'string' ? JSON.parse(body) : body;

// Extract message details
const messageData = {
  chatId: data.message?.chat?.id,
  userId: data.message?.from?.id,
  username: data.message?.from?.username || data.message?.from?.first_name || 'Unknown',
  firstName: data.message?.from?.first_name || '',
  messageText: data.message?.text || '',
  messageId: data.message?.message_id,
  timestamp: new Date().toISOString()
};

// Return extracted data
return {
  json: messageData
};

// Simple in-memory conversation history
// For production, use Redis or a database

const userId = $json.userId;
const storageKey = `history_${userId}`;

// Get history from workflow static data
let history = [];

if ($getWorkflowStaticData('global')[storageKey]) {
  history = JSON.parse($getWorkflowStaticData('global')[storageKey]);
}

return {
  json: {
    ...$json,
    conversationHistory: history
  }
};

// FAQ Knowledge Base
const FAQs = [
  {
    keywords: ['hours', 'open', 'timing', 'schedule', 'when'],
    answer: '🕐 We are open Monday-Friday: 9 AM - 6 PM, Saturday: 10 AM - 4 PM. Closed on Sundays.'
  },
  {
    keywords: ['price', 'cost', 'pricing', 'fee', 'how much'],
    answer: '💰 Our pricing starts at $49/month for the basic plan, $99/month for pro, and custom pricing for enterprise. Visit our website for detailed pricing.'
  },
  {
    keywords: ['contact', 'email', 'phone', 'reach', 'call'],
    answer: '📞 You can reach us at support@example.com or call +1-234-567-8900 during business hours.'
  },
  {
    keywords: ['return', 'refund', 'money back', 'guarantee'],
    answer: '💵 We offer a 30-day money-back guarantee. Contact our support team to initiate a refund.'
  },
  {
    keywords: ['shipping', 'delivery', 'ship', 'deliver'],
    answer: '📦 We ship worldwide. Domestic orders: 3-5 business days. International: 7-14 business days.'
  },
  {
  keywords: ['hello', 'hi there', 'hey there', '/start'],
  answer: '👋 Hello!...'
}
];

const userMessage = $json.messageText.toLowerCase();
let faqMatch = null;

// Check if user message matches any FAQ
for (const faq of FAQs) {
  if (faq.keywords.some(keyword => userMessage.includes(keyword))) {
    faqMatch = faq.answer;
    break;
  }
}

return {
  json: {
    ...$json,
    faqMatch: faqMatch,
    needsAI: !faqMatch
  }
};

// Format messages for OpenAI
const messages = [
  {
    role: 'system',
    content: `You are a helpful customer support assistant. Answer user questions professionally and concisely.

If you cannot answer a question with certainty or it requires account-specific information, say: "I'll need to escalate this to a human agent for accurate assistance."

Keep responses under 200 words.`
  }
];

// Add conversation history (last 10 messages)
if ($json.conversationHistory && $json.conversationHistory.length > 0) {
  messages.push(...$json.conversationHistory.slice(-10));
}

// Add current user message
messages.push({
  role: 'user',
  content: $json.messageText
});

return {
  json: {
    ...$json,
    messages: messages
  }
};

const response = $json.botResponse || '';

// Check if AI wants to escalate
const escalationKeywords = [
  'escalate',
  'human agent',
  'transfer',
  'speak to someone',
  'talk to human'
];

const needsEscalation = escalationKeywords.some(keyword => 
  response.toLowerCase().includes(keyword)
);

return {
  json: {
    ...$json,
    botResponse: response,
    escalated: needsEscalation
  }
};

const botResponse = $json.botResponse || $json.faqMatch;
const userId = $json.userId;
const userMessage = $json.messageText;

// Get existing history
let history = $json.conversationHistory || [];

// Add new messages
history.push({
  role: 'user',
  content: userMessage
});

history.push({
  role: 'assistant',
  content: botResponse
});

// Keep only last 20 messages (10 exchanges)
if (history.length > 20) {
  history = history.slice(-20);
}

// Store in workflow static data
const storageKey = `history_${userId}`;
$getWorkflowStaticData('global')[storageKey] = JSON.stringify(history);

return {
  json: {
    ...$json,
    botResponse: botResponse,
    conversationHistory: history
  }
};

const previousData = $('Format OpenAI Messages').item.json;
const groqResponse = $json.choices[0].message.content;

return {
  json: {
    ...previousData,
    botResponse: groqResponse
  }
};
